#include<bits/stdc++.h>
using namespace std;
int dx[] = {1, 0, -1, 0};
int dy[] = {0, 1, 0, -1};
char a[2001][2001];int n,m,t;
int fang[2001][2001];
bool v[2001][2001];
void print(int x,int y){
    if(x==1&&y==1) return;
    else{
        if(fang[x][y]==0){
            print(x-1,y);
            cout<<"D";
        }else if(fang[x][y]==1){
            print(x,y-1);
            cout<<"R";
        }else if(fang[x][y]==2){
            print(x+1,y);
            cout<<"U";
        }else if(fang[x][y]==3){
            print(x,y+1);
            cout<<"L";
        }
        return;}
}

int bfs() {
	queue<int> q[4];
		q[0].push(1);
	q[1].push(1);
	q[2].push(0);
	q[3].push(a[1][1]-'0');
	v[1][1]=1;
	while (!q[0].empty()) {
		int x = q[0].front();
		int y = q[1].front();
		bool flag=q[3].front();
		int srtp = q[2].front();
        q[0].pop();
        q[1].pop();
        q[2].pop();
        q[3].pop();
        //cout<<srtp<<"\n";
		if(x==n&&y==m) return srtp;
		for (int i = 0; i < 4; i++) {
			int mx=dx[i]+x;
			int my=dy[i]+y;

			if(mx>n||my>m||mx<=0||my<=0) continue;

			if((a[mx][my]-'0'==(!flag))&&!v[mx][my]){
                fang[mx][my]=i;
				v[mx][my]=1;
				q[0].push(mx);
				q[1].push(my);
				q[2].push(srtp+1);
				q[3].push(!flag);
			}
		}
	}
	return -1;
}
int main() {
	cin>>t;
	while(t--){
		cin>>n>>m;
		for(int i=1;i<=n;i++){
			for(int j=1;j<=m;j++){
				cin>>a[i][j];
			}
		}
		memset(v,0,sizeof(v));
        int ans=bfs();
		cout<<ans<<"\n";
        if(ans!=-1) print(n,m);
		if(ans!=-1) cout<<'\n';
	}
	return 0;
}
